#include <stdio.h>
#include <stdlib.h>

int** createGraph(int n, int m) {
    int** graph = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        graph[i] = (int*)malloc(m * sizeof(int));
    }
    return graph;
}

int isValid(int** graph, int n, int m, int country) {
    // Check if the current country can be placed in the current room
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (graph[i][j] == country) {
                // Check adjacent rooms
                if (i > 0 && graph[i - 1][j] == country) return 0;
                if (i < n - 1 && graph[i + 1][j] == country) return 0;
                if (j > 0 && graph[i][j - 1] == country) return 0;
                if (j < m - 1 && graph[i][j + 1] == country) return 0;
            }
        }
    }
    return 1;
}

int solve(int** graph, int n, int m, int* countries, int C, int index) {
    if (index == C) {
        // Print the solution
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                printf("%d ", graph[i][j]);
            }
            printf("\n");
        }
        return 1;
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (graph[i][j] == 0) {
                graph[i][j] = countries[index];
                if (isValid(graph, n, m, countries[index])) {
                    if (solve(graph, n, m, countries, C, index + 1)) return 1;
                }
                graph[i][j] = 0;
            }
        }
    }
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m, C;
        scanf("%d %d %d", &n, &m, &C);
        int* countries = (int*)malloc(C * sizeof(int));
        for (int i = 0; i < C; i++) {
            scanf("%d", &countries[i]);
        }
        int** graph = createGraph(n, m);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                graph[i][j] = 0;
            }
        }
        if (!solve(graph, n, m, countries, C, 0)) {
            printf("-1\n");
        }
        free(countries);
        for (int i = 0; i < n; i++) {
            free(graph[i]);
        }
        free(graph);
    }
    return 0;
}

